// Extract client.id from insert response
const data = $input.first().json;
const row = Array.isArray(data) ? data[0] : data;
const webhook = $node['Webhook: Client Onboard'].json.body;
return [{
  json: {
    client_id: row.id,
    client: row,
    webhook
  }
}];

// Extract brand_profile.id from insert response
const data = $input.first().json;
const row = Array.isArray(data) ? data[0] : data;
const prev = $('Parse Client ID').first().json;
return [{
  json: {
    client_id: prev.client_id,
    brand_id: row.id,
    brand: row,
    webhook: prev.webhook
  }
}];

// Extract offer_context.id from insert response
const data = $input.first().json;
const row = Array.isArray(data) ? data[0] : data;
const prev = $('Parse Brand ID').first().json;
return [{
  json: {
    client_id: prev.client_id,
    brand_id: prev.brand_id,
    offer_id: row.id,
    offer: row,
    webhook: prev.webhook
  }
}];

// Build the 8-step onboarding checklist for this client
const clientId = $('Parse Client ID').first().json.client_id;
const steps = [
  'Client intake & brand profile',
  'Offer context & positioning',
  'Swipe file curation',
  'Concept generation (week 1 batch)',
  'Copy generation',
  'Image render & review',
  'Meta ad upload & launch',
  'Reporting & iteration'
];
const now = new Date().toISOString();
const stepRows = steps.map((name, i) => ({
  client_id: clientId,
  step_number: i + 1,
  step_name: name,
  status: i === 0 ? 'in_progress' : 'pending',
  started_at: i === 0 ? now : null
}));

return [{
  json: {
    client_id: clientId,
    brand_id: $json.brand_id,
    offer_id: $json.offer_id,
    webhook: $json.webhook,
    steps: stepRows
  }
}];

// Final response payload
const clientId = $('Parse Client ID').first().json.client_id;
const brandId = $('Parse Brand ID').first().json.brand_id;
const offerId = $('Parse Offer ID').first().json.offer_id;
const vercel = $input.first().json || {};

return [{
  json: {
    success: true,
    client_id: clientId,
    brand_id: brandId,
    offer_id: offerId,
    vercel: vercel && vercel.success ? vercel : null
  }
}];
